+            if sym.is_null() { return std::ptr::null_mut(); }
+            let f: F = unsafe { std::mem::transmute(sym) };
+            unsafe { f( $($pname),* ) }
+        }
+    };
+    // Pattern 6: function returning u16 (pmap_getport)
+    ($name:ident ( $($pname:ident : $pty:ty),* ) -> u16) => {
+        #[cfg_attr(not(debug_assertions), unsafe(no_mangle))]
